function handleUploadedFile(e,a){let r=new FileReader;r.readAsDataURL(e),r.onload=(()=>{a.removeClass("dragover");let t=atob(r.result.split(";base64,").pop());a.trigger("upload",[{name:e.name,content:t,file:e}])})}function closePopup(){let e=$(".popup.active");e.removeClass("active"),$("body").css("overflow",""),$(e).trigger("close")}function openPopup(e){$(`#${e}`).addClass("active"),$("body").css("overflow","hidden")}$(".drag-drop-area").on("dragover",e=>{let a=$(e.target);e.preventDefault(),e.stopPropagation(),a.addClass("dragover")}),$(".drag-drop-area").on("dragleave",e=>{let a=$(e.target);e.preventDefault(),e.stopPropagation(),a.removeClass("dragover")}),$(".drag-drop-area").on("drop",e=>{let a=$(e.target);e.preventDefault(),e.stopPropagation(),a.removeClass("dragover"),handleUploadedFile(e.originalEvent.dataTransfer.files[0],a)}),$(".drag-drop-area").on("click",e=>{let a=$(e.currentTarget),r=$(`<input type="file" accept="${a.attr("accept").replace(/\*/g,"")}">`);r.trigger("click"),r.on("change",()=>{handleUploadedFile(r.prop("files")[0],a)})}),$(".drag-drop-area").each((e,a)=>{let r=$(a),t=r.attr("accept");r.html(`<i>(${t})</i>`)}),$("toggle").on("click",e=>{e.preventDefault();let a=$(e.target),r="true"===a.attr("value");a.attr("value",!r),a.trigger("toggle",[{value:!r}])}),$("img").on("error",e=>{e.currentTarget.remove()});